import type { Story, StoryQuiz } from "@/app/stories";

/* Hand-written stories — 50 per level, each with its own plot, title and
   quiz. Sentence length and vocabulary step up through the years. */

function S(
  id: string,
  title: string,
  emoji: string,
  lexile: number,
  text: string,
  question: string,
  options: [string, string][],
  answer: number,
): Story {
  const quiz: StoryQuiz = {
    question,
    options: options.map(([e, l]) => ({ emoji: e, label: l })),
    answer,
  };
  return { id, title, emoji, lexile, pages: [{ text, emoji }], quiz };
}

